    }

    // First count the number of tabs to determine the size of the new string
    int tabs = 0;
    int length = 0;
    for (const char* p = inputString; *p; p++)
    {
        if (*p == '\t')
        {
            tabs++;
        }
        length++;
    }

    // Allocate memory for the new string
    char* result = (char*)malloc(length + tabs * (tabSize - 1) + 1);
    if (result == NULL)
    {
        return NULL;
    }

    // Replace tabs with spaces
    int pos = 0;
    for (const char* p = inputString; *p; p++)
    {
        if (*p == '\t')
        {
            for (int i = 0; i < tabSize; i++)
            {
                result[pos++] = ' ';
            }
        }
        else
        {
            result[pos++] = *p;
        }
    }

